function savePlan(){var id=document.getElementById('planEditId').value;var featsRaw=document.getElementById('planFeatures').value||'';var features=featsRaw.split(/\r?\n/).map(function(s){return s.trim();}).filter(Boolean);var body={name:(document.getElementById('planName').value||'').trim(),tagline:(document.getElementById('planTagline').value||'').trim()||null,description:(document.getElementById('planDescription').value||'').trim()||null,stripe_price_id:(document.getElementById('planStripePriceId').value||'').trim()||null,amount_cents:parseInt(document.getElementById('planAmount').value,10)||0,currency:(document.getElementById('planCurrency').value||'aed').toLowerCase().trim(),interval:document.getElementById('planInterval').value==='year'?'year':'month',features:features.length?features:null,sort_order:parseInt(document.getElementById('planSort').value,10)||100,is_active:document.getElementById('planActive').checked,country_id:(document.getElementById('planCountry')&&document.getElementById('planCountry').value)||null,};if(!body.name){showToast('Plan name required',true);return;}
var url=id?(ATP_API+'/billing/admin/plans/'+id):(ATP_API+'/billing/admin/plans');var method=id?'PATCH':'POST';fetch(url,{method:method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Plan saved');cancelPlanForm();loadPlansAdmin();}).catch(function(e){showToast('❌ '+e.message,true);});}
